{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 1f);
var density = GetFloat(parameters, "density", 0.5f);
var sharpness = GetFloat(parameters, "sharpness", 0.5f);
var coverage = GetFloat(parameters, "coverage", 0.5f);
var cloudType = GetChoice(parameters, "cloudType", "cumulus");
var stretch = GetFloat(parameters, "stretch", 0f);
var octaves = Math.Max(1, GetInt(parameters, "octaves", 4));
var gradientMode = GetChoice(parameters, "gradientMode", "dualColor");
var skyColor = GetColor(parameters, "skyColor", Color.FromRgb(100, 150, 255));
var cloudColor = GetColor(parameters, "cloudColor", Color.FromRgb(255, 255, 255));
var highlightColor = GetColor(parameters, "highlightColor", Color.FromRgb(255, 255, 255));
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var skyR = skyColor.R / 255f; var skyG = skyColor.G / 255f; var skyB = skyColor.B / 255f;
var cR = cloudColor.R / 255f; var cG = cloudColor.G / 255f; var cB = cloudColor.B / 255f;
var hR = highlightColor.R / 255f; var hG = highlightColor.G / 255f; var hB = highlightColor.B / 255f;
var period = Math.Max(1, (int)MathF.Round(scale * 2f));

// Cloud-type-specific noise tuning
var persistence = cloudType switch
{
    "stratus" => 0.7f,   // Smoother, more merged
    "cirrus" => 0.45f,  // Finer, more fragile
    "mixed" => 0.6f,
    _ => 0.6f          // cumulus: default
};

var lacunarity = cloudType switch
{
    "cirrus" => 2.8f,   // Higher frequency detail for wisps
    "mixed" => 2.3f,
    _ => 2f            // cumulus/stratus: standard
};

// Stretch: apply anisotropic UV scaling (stretch > 0 elongates horizontally for stratus)
var stretchFactor = 1f + stretch * 3f;

buffer.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size;
    var v = y / (float)size;

    // Apply stretching: horizontal stretch for stratus, can also do vertical
    var nu = u * scale;
    var nv = v * scale * (1f / stretchFactor);

    // Base cloud shape from low-frequency noise
    var baseNoise = TileableFractalNoise(
        nu * 2f * stretchFactor, nv * 2f,
        Math.Max(1, (int)(period * stretchFactor)), octaves, persistence, lacunarity, seed);

    // Apply coverage: shift the noise baseline
    var shifted = baseNoise - (1f - coverage);

    // Apply density: scale the noise
    shifted *= density * 2f;

    // Detail: high-frequency octaves for fluffy edges (scale detail with cloud type)
    var detailScales = cloudType switch
    {
        "stratus" => 0.3f,  // Less detail for smooth stratus
        "cirrus" => 0.8f,  // More detail for wispy cirrus
        _ => 0.5f
    };

    var detailVal = 0f;
    var detailOctaves = cloudType == "cirrus" ? 3 : 2;
    for (var d = 0; d < detailOctaves; d++)
    {
        var f = MathF.Pow(3f, d + 1);
        var amp = MathF.Pow(0.5f, d + 1);
        detailVal += TileableFractalNoise(
            nu * f * stretchFactor, nv * f,
            Math.Max(1, (int)(period / (f / stretchFactor))), 1, 0.5f, 2f, seed + 1000 + d * 137) * amp;
    }

    // Combine base and detail
    var cloud = shifted + detailVal * detailScales * (1f - sharpness * 0.5f);

    // Soft threshold
    var cloudiness = (cloud + 0.3f) / Math.Max(0.001f, 0.6f + sharpness * 0.4f);
    cloudiness = Math.Clamp(cloudiness, 0f, 1f);

    // Smoothstep for softer cloud edges
    cloudiness = cloudiness * cloudiness * (3f - 2f * cloudiness);

    if (invert) cloudiness = 1f - cloudiness;

    float r, g, b;

    if (gradientMode == "gradientRamp" && (hR != cR || hG != cG || hB != cB))
    {
        // Three-color gradient: sky -> cloud -> highlight based on density
        // cloudiness 0-0.5: sky to cloud, 0.5-1.0: cloud to highlight
        var t = cloudiness;
        if (t < 0.5f)
        {
            var t2 = t * 2f;
            r = Lerp(skyR, cR, t2);
            g = Lerp(skyG, cG, t2);
            b = Lerp(skyB, cB, t2);
        }
        else
        {
            var t2 = (t - 0.5f) * 2f;
            r = Lerp(cR, hR, t2);
            g = Lerp(cG, hG, t2);
            b = Lerp(cB, hB, t2);
        }
    }
    else
    {
        // Dual-color: sky -> cloud
        r = Lerp(skyR, cR, cloudiness);
        g = Lerp(skyG, cG, cloudiness);
        b = Lerp(skyB, cB, cloudiness);
    }

    buffer.SetPixel(x, y, r, g, b, 1f);
});

return buffer;
}
